"use client";

import { useState } from "react";
import Link from "next/link";
import { usePathname } from "next/navigation";

const NAV = [
  { label: "Modules",  href: "/features" },
  { label: "Pricing",  href: "/pricing" },
  { label: "About Us", href: "/about" },
  { label: "Careers",  href: "/about" },
  { label: "Contact",  href: "/contact" },
];

export default function HeaderLight() {
  const [menuOpen, setMenuOpen] = useState(false);
  const pathname = usePathname();

  return (
    <header className="bg-white border-b border-[--border] w-full z-50">
      <div className="container-xl flex items-center justify-between h-[70px]">
        {/* Logo */}
        <Link href="/" className="flex items-center gap-2 shrink-0">
          <svg width="26" height="26" viewBox="0 0 32 32" fill="none">
            <circle cx="16" cy="16" r="13" stroke="var(--primary)" strokeWidth="2" fill="none" />
            <ellipse cx="16" cy="16" rx="7" ry="13" stroke="var(--primary)" strokeWidth="1.5" fill="none" />
            <line x1="3" y1="16" x2="29" y2="16" stroke="var(--primary)" strokeWidth="1.5" />
          </svg>
          <span className="text-[19px] font-bold tracking-tight text-[--dark]">
            Sync<span className="text-[--primary]">Core</span>
          </span>
        </Link>

        {/* Desktop nav */}
        <nav className="hidden lg:flex items-center gap-8">
          {NAV.map((link) => (
            <Link
              key={link.href}
              href={link.href}
              className={`text-sm font-medium transition-colors hover:text-[--primary] ${
                pathname === link.href ? "text-[--primary]" : "text-[--dark]"
              }`}
            >
              {link.label}
            </Link>
          ))}
        </nav>

        {/* CTA + burger */}
        <div className="flex items-center gap-3">
          <Link
            href="/contact"
            className="hidden sm:inline-flex items-center gap-2 btn btn-sm btn-primary"
          >
            Request a Demo
          </Link>
          <button
            onClick={() => setMenuOpen(!menuOpen)}
            className="lg:hidden flex flex-col gap-[5px] w-6 cursor-pointer p-0.5"
            aria-label="Toggle menu"
          >
            {[0, 1, 2].map((i) => (
              <span
                key={i}
                className={`block h-[2px] bg-[--dark] rounded transition-all duration-300
                  ${i === 0 && menuOpen ? "rotate-45 translate-y-[7px]" : ""}
                  ${i === 1 && menuOpen ? "opacity-0 scale-x-0" : ""}
                  ${i === 2 && menuOpen ? "-rotate-45 -translate-y-[7px]" : ""}`}
              />
            ))}
          </button>
        </div>
      </div>

      {/* Mobile drawer */}
      {menuOpen && (
        <div className="lg:hidden border-t border-[--border] bg-white shadow-lg">
          <div className="container-xl py-4 flex flex-col gap-1">
            {NAV.map((link) => (
              <Link
                key={link.href}
                href={link.href}
                onClick={() => setMenuOpen(false)}
                className={`py-2.5 px-3 text-sm font-medium rounded transition-colors hover:bg-[--primary]/8 hover:text-[--primary] ${
                  pathname === link.href ? "text-[--primary]" : "text-[--dark]"
                }`}
              >
                {link.label}
              </Link>
            ))}
            <Link
              href="/contact"
              onClick={() => setMenuOpen(false)}
              className="mt-3 inline-flex btn btn-sm btn-primary w-fit"
            >
              Request a Demo
            </Link>
          </div>
        </div>
      )}
    </header>
  );
}
