"use client";

import { useState } from "react";
import Link from "next/link";

const NAV = [
  { label: "Modules",  href: "/features" },
  { label: "Pricing",  href: "/pricing" },
  { label: "About",    href: "/about" },
  { label: "Contact",  href: "/contact" },
];

export default function HeaderMinimal() {
  const [menuOpen, setMenuOpen] = useState(false);

  return (
    <header className="bg-white w-full z-50">
      <div className="container-xl flex items-center justify-between h-[60px]">
        {/* Logo — text only */}
        <Link href="/" className="text-[17px] font-bold tracking-tight text-[--dark]">
          Sync<span className="text-[--primary]">Core</span>
        </Link>

        {/* Desktop nav */}
        <nav className="hidden md:flex items-center gap-7">
          {NAV.map((link) => (
            <Link
              key={link.href}
              href={link.href}
              className="text-xs font-semibold tracking-[.06em] uppercase text-[--text] hover:text-[--primary] transition-colors"
            >
              {link.label}
            </Link>
          ))}
        </nav>

        {/* CTA + burger */}
        <div className="flex items-center gap-3">
          <Link
            href="/contact"
            className="hidden sm:inline-flex btn btn-sm btn-outline"
          >
            Get Started
          </Link>
          <button
            onClick={() => setMenuOpen(!menuOpen)}
            className="md:hidden flex flex-col gap-[5px] w-5 cursor-pointer"
            aria-label="Toggle menu"
          >
            {[0, 1, 2].map((i) => (
              <span
                key={i}
                className={`block h-[2px] bg-[--dark] rounded transition-all duration-300
                  ${i === 0 && menuOpen ? "rotate-45 translate-y-[7px]" : ""}
                  ${i === 1 && menuOpen ? "opacity-0 scale-x-0" : ""}
                  ${i === 2 && menuOpen ? "-rotate-45 -translate-y-[7px]" : ""}`}
              />
            ))}
          </button>
        </div>
      </div>

      {/* Thin bottom border */}
      <div className="border-b border-[--border]" />

      {/* Mobile drawer */}
      {menuOpen && (
        <div className="md:hidden border-b border-[--border] bg-white">
          <div className="container-xl py-3 flex flex-col gap-0.5">
            {NAV.map((link) => (
              <Link
                key={link.href}
                href={link.href}
                onClick={() => setMenuOpen(false)}
                className="py-2 px-2 text-sm font-medium text-[--dark] hover:text-[--primary] transition-colors"
              >
                {link.label}
              </Link>
            ))}
          </div>
        </div>
      )}
    </header>
  );
}
